INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('importâncias despendidas com prémios de seguros de acidentes pessoais e seguros de vida que garantam exclusivamente os riscos de morte, invalidez ou reforma por velhice, neste último caso desde que o benefício seja garantido após os 55 anos de idade e cinco anos de duração do contrato, relativos ao sujeito passivo ou aos seus dependentes, pagos por aquele ou por terceiros, desde que, neste caso, tenham sido, comprovadamente, tributados como rendimento do sujeito passivo, com o limite de (euro) 54,89, tratando-se de sujeitos passivos não casados ou separados judicialmente de pessoas e bens, ou de (euro) 109,78, tratando-se de sujeitos passivos casados e não separados judicialmente de pessoas e bens. 
