INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' sede ou direcção efectiva em território português, são deduzidos os rendimentos, incluídos na base tributável, correspondentes a lucros distribuídos, desde que sejam verificados os seguintes requisitos: 
