INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('te mínimo, optar, no prazo e nos termos previstos na alínea b) do n.º 7, pela aplicação do regime geral de determinação do lucro tributável, ainda que não tenha decorrido o período mínimo de permanência no regime simplificado. 
