INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' não possuam o estatuto de operador registado, a que se refere o artigo 15.º do Decreto-Lei n.º 40/93, de 18 de Fevereiro, deverão pagar o imposto devido pelas aquisições intracomunitárias de veículos automóveis sujeitos a imposto automóvel junto das entidades competentes para a cobrança deste imposto. 
