INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('essas condições, os rendimentos referidos no n.º 7 da mesma alínea, quando os serviços de que derivam, sendo realizados integralmente fora do território português, não respeitem a bens situados nesse território nem estejam relacionados com estudos, projectos, apoio técnico ou à gestão, serviços de contabilidade ou auditoria e serviços de consultoria, organização, investigação e desenvolvimento em qualquer domínio. 
