INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('acordo homologado nos termos da lei civil, salvo nos casos em que o seu beneficiário faça parte do mesmo agregado familiar ou relativamente ao qual estejam previstas deduções no artigo 78.º 
  Artigo 68.º
  Taxas gerais
  1 - As taxas do imposto são as constantes da tabela seguinte:
