INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('idas no artigo 2.º da Directiva n.º 90/435/CEE, de 23 de Julho, coloque à disposição de entidade residente noutro Estado membro da União Europeia ou de um estabelecimento estável, situado noutro Estado membro, de uma entidade residente num Estado membro que esteja nas mesmas condições e que detenha directamente, ou por intermédio de um estabelecimento estável situado no território de um Estado membro, uma participação no capital da primeira não inferior a 20 e quando esta participação não tenha permanecido na sua titularidade, de modo ininterrupto, durante os dois anos anteriores à data da sua colocação à disposição. 
