INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('IA dos veículos automóveis, novos ou usados, abrangidos pela tabela I, é de natureza específica e variável em função dos escalões de cilindrada e das emissões de dióxido de carbono (CO(índice 2)), em ciclo combinado de ensaios, constantes das respectivas homologações técnicas ou, no caso de não constarem, resultantes de medição efectiva, consoante o combustível consumido no respectivo sistema de propulsão, sendo o das restantes categorias determinado exclusivamente pelos escalões de cilindrada, segundo as tabelas III, IV, V e VI anexas ao presente diploma, que dele fazem parte integrante, correspondendo a tabela II às fórmulas de conversão em centímetros cúbicos a aplicar aos veículos automóveis não convencionais. 
