INSERT OR IGNORE INTO Articles (text, category_id) VALUES ('- A dedução a que se refere o n.º 1 é reduzida a 50 quando os rendimentos provenham de lucros que não tenham sido sujeitos a tributação efectiva, excepto quando a beneficiária seja uma sociedade gestora de participações sociais. 
