INSERT OR IGNORE INTO Articles (text, category_id) VALUES (' devolução, total ou parcial, do imposto retido e pago na parte em que seja superior ao que resultaria da aplicação da tabela de taxas prevista no n.º 1 do artigo 68.º, tendo em consideração todos os rendimentos, incluindo os obtidos fora deste território, nas mesmas condições que são aplicáveis aos residentes.
